import React, { useState, useEffect } from 'react';
import Sidebar from '../components/Sidebar';
import Navbar from '../components/Navbar';

const Payments = () => {
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  // Mock payment data
  const mockPayments = [
    {
      id: 1,
      bookingId: 1,
      carName: 'Tesla Model S',
      amount: 750,
      method: 'Credit Card',
      status: 'completed',
      date: '2024-01-10',
      transactionId: 'TXN-001-2024'
    },
    {
      id: 2,
      bookingId: 2,
      carName: 'BMW X5',
      amount: 600,
      method: 'Debit Card',
      status: 'completed',
      date: '2023-12-28',
      transactionId: 'TXN-002-2023'
    },
    {
      id: 3,
      bookingId: 3,
      carName: 'Mercedes C-Class',
      amount: 200,
      method: 'Credit Card',
      status: 'pending',
      date: '2024-01-20',
      transactionId: 'TXN-003-2024'
    },
    {
      id: 4,
      bookingId: 4,
      carName: 'Audi A4',
      amount: 400,
      method: 'Credit Card',
      status: 'refunded',
      date: '2023-12-10',
      transactionId: 'TXN-004-2023'
    }
  ];

  useEffect(() => {
    // Simulate loading data
    setTimeout(() => {
      setPayments(mockPayments);
      setLoading(false);
    }, 500);
  }, []);

  const filteredPayments = payments.filter(payment => {
    if (filter === 'all') return true;
    return payment.status === filter;
  });

  const getStatusBadge = (status) => {
    const statusClasses = {
      completed: { background: '#10b981', color: 'white' },
      pending: { background: '#f59e0b', color: 'white' },
      refunded: { background: '#6b7280', color: 'white' },
      failed: { background: '#ef4444', color: 'white' }
    };
    const style = statusClasses[status] || statusClasses.completed;
    return (
      <span style={{...styles.statusBadge, ...style}}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </span>
    );
  };

  const totalSpent = payments
    .filter(p => p.status === 'completed')
    .reduce((sum, p) => sum + p.amount, 0);

  const totalPending = payments
    .filter(p => p.status === 'pending')
    .reduce((sum, p) => sum + p.amount, 0);

  return (
    <div style={styles.container}>
      <Navbar />
      <Sidebar />
      
      <div style={styles.dashboardContent}>
        <div style={styles.pageHeader}>
          <h1 style={styles.pageTitle}>Payments</h1>
          <p style={styles.pageSubtitle}>View your payment history and manage transactions</p>
        </div>

        {/* Payment Stats */}
        <div style={styles.paymentStats}>
          <div style={styles.paymentStatCard}>
            <div style={styles.statIcon}>💵</div>
            <div style={styles.statDetails}>
              <h3>₱{totalSpent.toLocaleString()}</h3>
              <p>Total Spent</p>
            </div>
          </div>
          
          <div style={styles.paymentStatCard}>
            <div style={styles.statIcon}>⏳</div>
            <div style={styles.statDetails}>
              <h3>₱{totalPending.toLocaleString()}</h3>
              <p>Pending Payments</p>
            </div>
          </div>
          
          <div style={styles.paymentStatCard}>
            <div style={styles.statIcon}>📊</div>
            <div style={styles.statDetails}>
              <h3>{payments.length}</h3>
              <p>Total Transactions</p>
            </div>
          </div>
        </div>

        {/* Filter Tabs */}
        <div style={styles.filterTabs}>
          {['all', 'completed', 'pending', 'refunded'].map(f => (
            <button 
              key={f}
              style={{
                ...styles.filterTab,
                ...(filter === f ? styles.filterTabActive : {})
              }}
              onClick={() => setFilter(f)}
            >
              {f.charAt(0).toUpperCase() + f.slice(1)} ({payments.filter(p => f === 'all' || p.status === f).length})
            </button>
          ))}
        </div>

        {/* Payments List */}
        {loading ? (
          <div style={styles.loading}>Loading payments...</div>
        ) : filteredPayments.length === 0 ? (
          <div style={styles.emptyState}>
            <p>No payments found</p>
          </div>
        ) : (
          <div style={styles.paymentsList}>
            <table style={styles.table}>
              <thead>
                <tr>
                  <th style={styles.th}>Date</th>
                  <th style={styles.th}>Car</th>
                  <th style={styles.th}>Amount</th>
                  <th style={styles.th}>Method</th>
                  <th style={styles.th}>Status</th>
                  <th style={styles.th}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredPayments.map(payment => (
                  <tr key={payment.id} style={styles.tr}>
                    <td style={styles.td}>{payment.date}</td>
                    <td style={styles.td}>
                      <div style={styles.paymentCar}>
                        <strong>{payment.carName}</strong>
                        <span style={styles.bookingId}>Booking #{payment.bookingId}</span>
                      </div>
                    </td>
                    <td style={{...styles.td, fontWeight: 'bold'}}>₱{payment.amount.toLocaleString()}</td>
                    <td style={styles.td}>{payment.method}</td>
                    <td style={styles.td}>{getStatusBadge(payment.status)}</td>
                    <td style={styles.td}>
                      <button style={styles.btnSecondary}>
                        View Receipt
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #e9eefb, #f9fbfe)',
  },
  dashboardContent: {
    marginLeft: '250px',
    marginTop: '60px',
    padding: '30px',
    overflowY: 'auto',
  },
  pageHeader: {
    marginBottom: '20px',
  },
  pageTitle: {
    color: '#121253',
    fontSize: '28px',
    fontWeight: '700',
    margin: '0 0 5px 0',
  },
  pageSubtitle: {
    color: '#555',
    fontSize: '14px',
    margin: 0,
  },
  paymentStats: {
    display: 'flex',
    gap: '20px',
    marginBottom: '30px',
    flexWrap: 'wrap',
  },
  paymentStatCard: {
    background: 'white',
    padding: '20px',
    borderRadius: '8px',
    boxShadow: '0 5px 15px rgb(56 56 92 / 0.1)',
    display: 'flex',
    alignItems: 'center',
    gap: '15px',
    flex: '1',
    minWidth: '200px',
  },
  statIcon: {
    fontSize: '30px',
  },
  statDetails: {
    color: '#121253',
  },
  filterTabs: {
    display: 'flex',
    gap: '10px',
    marginBottom: '20px',
    flexWrap: 'wrap',
  },
  filterTab: {
    padding: '10px 20px',
    border: 'none',
    background: '#e9eefb',
    borderRadius: '6px',
    cursor: 'pointer',
    fontWeight: '500',
    color: '#555',
    transition: 'all 0.3s ease',
  },
  filterTabActive: {
    background: '#3f42c7',
    color: 'white',
  },
  loading: {
    textAlign: 'center',
    padding: '40px',
    color: '#555',
  },
  emptyState: {
    textAlign: 'center',
    padding: '40px',
    color: '#555',
    background: 'white',
    borderRadius: '8px',
  },
  paymentsList: {
    background: 'white',
    borderRadius: '8px',
    boxShadow: '0 5px 15px rgb(56 56 92 / 0.1)',
    overflow: 'hidden',
  },
  table: {
    width: '100%',
    borderCollapse: 'collapse',
  },
  th: {
    padding: '15px',
    textAlign: 'left',
    background: '#f8f9fa',
    color: '#555',
    fontWeight: '600',
    fontSize: '14px',
  },
  tr: {
    borderBottom: '1px solid #eee',
  },
  td: {
    padding: '15px',
    fontSize: '14px',
    color: '#555',
  },
  paymentCar: {
    display: 'flex',
    flexDirection: 'column',
  },
  bookingId: {
    fontSize: '12px',
    color: '#888',
  },
  statusBadge: {
    padding: '5px 12px',
    borderRadius: '20px',
    fontSize: '12px',
    fontWeight: '600',
  },
  btnSecondary: {
    background: '#6b7280',
    border: 'none',
    color: 'white',
    padding: '8px 16px',
    borderRadius: '6px',
    fontWeight: '600',
    cursor: 'pointer',
    fontSize: '12px',
  },
};

export default Payments;
